// Normalize incoming payload and compute derived values
const body = $input.first().json.body || $input.first().json;

const email = (body.email || '').toLowerCase().trim();
const firstName = (body.firstName || '').trim();
const companyName = (body.companyName || '').trim();
const source = (body.source || 'site').trim();
const answers = body.answers || {};

// Compute score (count of checked answers)
const score = Object.values(answers).filter(Boolean).length;

// Determine readiness tier
let tier = 'Early Stage';
let tierMessage = '';
if (score >= 16) {
  tier = 'Highly Ready';
  tierMessage = 'You have strong foundations in place. Our conversation will focus on which automations will move the needle fastest.';
} else if (score >= 11) {
  tier = 'Ready for Quick Wins';
  tierMessage = 'You are in a great position to implement high-impact automations. David will focus on the 2-3 quick wins that will give you the best return immediately.';
} else if (score >= 6) {
  tier = 'Building Foundation';
  tierMessage = 'You have key gaps that, once filled, will unlock significant efficiency. David will recommend the foundational pieces to prioritize first.';
} else {
  tier = 'Early Stage';
  tierMessage = 'You are early in your automation journey — which is actually an advantage. David will help you plan a simple roadmap that avoids over-engineering.';
}

// Map source to deal tier for CRM
let crmDealTier = 'Lead';
if (source === 'customer') crmDealTier = 'Post-Payment';
else if (source === 'audit') crmDealTier = 'Audit Requested';

// Summarize answered questions for David's notification
const answeredYes = Object.entries(answers)
  .filter(([, v]) => v === true)
  .map(([k]) => k)
  .join(', ') || 'None';

const submittedAt = new Date().toISOString();
const submittedReadable = new Date().toLocaleString('en-US', {
  timeZone: 'America/New_York',
  dateStyle: 'medium',
  timeStyle: 'short'
});

return [{
  json: {
    email,
    firstName,
    companyName,
    source,
    score,
    tier,
    tierMessage,
    crmDealTier,
    answeredYes,
    answers,
    submittedAt,
    submittedReadable,
    hasCompany: companyName.length > 0
  }
}];

